package org.tsalko.leetcode;

import org.junit.jupiter.api.Assertions;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.Arguments;
import org.junit.jupiter.params.provider.MethodSource;

import java.util.stream.Stream;

public class LeetCode005_Test {

    static Stream<Arguments> dataProvider() {
        return Stream.of(
                Arguments.of("babad", "bab"),
                Arguments.of("cbbd", "bb"),
                Arguments.of("bb", "bb"),
                Arguments.of("aaaa", "aaaa"),
                Arguments.of("tattarrattat", "tattarrattat"),
                Arguments.of("", "")
        );
    }

    @ParameterizedTest
    @MethodSource("dataProvider")
    public void test(String s, String expected) {
        Assertions.assertEquals(expected, new LeetCode005_LongestPalindromicSubstring().longestPalindrome(s));
    }

}
